from flask import Flask, request, jsonify
from google.cloud import secretmanager
import os

app = Flask(__name__)

# CORS headers
@app.after_request
def add_cors_headers(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    response.headers.add('Access-Control-Allow-Methods', 'GET, POST, OPTIONS')
    response.headers.add('Access-Control-Allow-Headers', 'Content-Type')
    return response

# Function to retrieve secrets securely
def get_secret(secret_id):
    client = secretmanager.SecretManagerServiceClient()
    name = f"projects/{os.environ['GCP_PROJECT']}/secrets/{secret_id}/versions/latest"
    response = client.access_secret_version(name=name)
    return response.payload.data.decode('UTF-8')

@app.route('/api/data', methods=['POST'])
def handle_data():
    if request.method == 'OPTIONS':
        return '', 204

    data = request.json
    if not data or 'input' not in data:
        return jsonify({'error': 'Invalid input'}), 400

    # Validate and process input
    user_input = data['input']
    if not isinstance(user_input, str) or len(user_input) > 100:
        return jsonify({'error': 'Input must be a string with max length 100'}), 400

    # Example of using a secret
    secret_value = get_secret('my_secret')

    # Process the input securely
    response_data = {'message': f'Processed input: {user_input}', 'secret': secret_value}
    return jsonify(response_data), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)